import{_ as e,p as l,q as i,a1 as r}from"./framework-e0dd9823.js";const t={},h=r('<h1 id="there-be-句型" tabindex="-1"><a class="header-anchor" href="#there-be-句型" aria-hidden="true">#</a> There be 句型</h1><p>“There be”句型表示“某时某地存在某人或者某物”，这种意识必须用“There be”句型表达，翻译成中文就是“什么地方有什么人或物”。但是这里的“有”强调“存在”的意义，而不是“拥有”，使用时注意和系动词“have”的区别。</p><p>句型结构：There be + 主语 + 状语</p><p>一般情况下，这个主语只能时普通名词，不定代词也可以做主语。主语前面可以加定语和某些不定代词，但是不饿能用定冠词“the”。</p><p>“there be”句型也有时态的变化，下面通过四个基本时态来讲解。</p><ol><li>一般现在时态</li></ol><ul><li>There is + a/an/one + 可数名词单数 + 地点状语</li><li>There is + 不可数名词 + 地点状语</li><li>There are + 大于 1 的限定词 + 可数名词复数 + 地点状语</li></ul><p>否定句：be 动词后面加 not</p><p>一般疑问句：be 动词移到句首</p><ol start="2"><li>一般过去时态</li></ol><ul><li>There was + a/an/one + 可数名词单数 + 地点状语 + 过去的时间状语</li><li>There was + 不可数名词 + 地点状语 + 过去的时间状语</li><li>There were + 大于 1 的限定词 + 可数名词复数 + 地点状语 + 过去的时间状语</li></ul><ol start="3"><li>一般将来时态</li></ol><ul><li>There will be + 名词 + 地点状语 + 将来的时间状语</li><li>There is going to be + 单数/不可数名词 + 地点状语 + 将来时间状语</li><li>There are going to be + 可数名词复数 + 地点状语 + 将来时间状语</li></ul><ol start="4"><li>现在完成时态</li></ol><ul><li>There has been + 单数/不可数名词 + 地点状语</li><li>There have been + 复数 + 地点状语</li></ul>',15),a=[h];function o(n,s){return l(),i("div",null,a)}const p=e(t,[["render",o],["__file","there-be.html.vue"]]);export{p as default};
